using namespace std;

int main() {

    return 0;
}

Binary Search Tree.solution:
#include <iostream>
using namespace std;

struct Node {
    int data;
    Node* left;
    Node* right;
};

bool search(Node* root, int target) {
    if (root == nullptr) return false;
    if (root->data == target) return true;
    if (target < root->data) return search(root->left, target);
    return search(root->right, target);
}

int main() {

    Node left{5, nullptr, nullptr};
    Node right{15, nullptr, nullptr};
    Node root{10, &left, &right};

    cout << (search(&root, 5) ? "Found" : "Not Found");

    return 0;
}

