BFS.solution:
#include <iostream>
#include <vector>
#include <queue>
using namespace std;

int main() {

    vector<vector<int>> graph(3);
    graph[0] = {1, 2};

    vector<bool> visited(3, false);
    queue<int> q;

    visited[0] = true;
    q.push(0);

    while (!q.empty()) {
        int node = q.front();
        q.pop();

        cout << node;
        if (!q.empty() || !graph[node].empty()) cout << " ";

        for (int neighbor : graph[node]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                q.push(neighbor);
            }
        }
    }

    return 0;
}

